{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを正式発足とし、キックオフとする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例会議を毎週水曜日の10時に開催する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "開発ベンダーとしてコマツバ・ソリューションズ社を採用する（ハギワラ技研はスケジュール、ツヅキシステムは予算超過のため除外）。",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D4",
      "content": "認証とマスタ配信の基盤について、サクラ商事との共同利用（第3案）を採用する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "既存のロール定義を流用し、新規設計は行わず、整理・改善は稼働後の運用課題として別立てする。",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D6",
      "content": "障害発生時の一次受け窓口を情報システム部からQAチーム（白鳥千夏氏ら）に変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "移行方式を段階移行（拠点を分けて順番に切り替える方式）とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "本番リリースの目標日程を9月末から10月15日に変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "システム切り替え作業を土曜日の深夜帯に実施する。",
      "decided_by": "沼田 賢一"
    }
  ],
